@dataclass
class StdTemplateInputs:
    # only user/tool/assistant
    messages: List[Dict[str, str]]
    # None: use default system; '': not use system
    system: Optional[str] = None
    tools: Optional[List[Tool]] = None

    label: Optional[int] = None
    channel: Optional[str] = None

    images: List[Union[str, Image.Image]] = field(default_factory=list)
    videos: List[str] = field(default_factory=list)
    audios: List[str] = field(default_factory=list)
    objects: Dict[str, Any] = field(default_factory=dict)

    margin: Optional[float] = None  # for reward modeling
    chat_template_kwargs: Dict[str, Any] = field(default_factory=dict)  # from dataset
    extra_kwargs: Dict[str, Any] = field(default_factory=dict)

    mm_processor_kwargs: Dict[str, Any] = field(default_factory=dict)

    def __post_init__(self):
        self.image_idx = 0
        self.audio_idx = 0
        self.video_idx = 0
        self.ref_idx = 0
        self.bbox_idx = 0
        if self.images and not isinstance(self.images, (list, tuple)):
            self.images = [self.images]
        if self.videos and not isinstance(self.videos, (list, tuple)):
            self.videos = [self.videos]
        if self.audios and not isinstance(self.audios, (list, tuple)):
            self.audios = [self.audios]

    def to_history(self):
        if not self.messages:
            return None
        return messages_to_history(self.messages)

    @property
    def is_multimodal(self):
        return bool(self.images or self.audios or self.videos or self.objects)

    @classmethod
    def from_dict(cls, inputs: Dict[str, Any]) -> 'StdTemplateInputs':
        inputs = deepcopy(inputs)
        kwargs = {}
        for key in ['label', 'channel', 'margin', 'rejected_response']:
            if key in inputs:
                kwargs[key] = inputs[key]
        messages = inputs['messages']
        tools = inputs.get('tools')
        objects = inputs.get('objects') or {}
        chat_template_kwargs = inputs.get('chat_template_kwargs') or {}

        if messages and messages[0]['role'] == 'system':
            message = messages.pop(0)
            system = message['content']
        else:
            system = None

        for message in messages:
            if message['role'] == 'tool_response':
                message['role'] = 'tool'
            if message['role'] in {'tool_call', 'tool'} and not isinstance(message['content'], str):
                message['content'] = json.dumps(message['content'], ensure_ascii=False)

        media_kwargs = StdTemplateInputs.remove_messages_media(messages)
        for k in list(media_kwargs.keys()):
            mm_data = media_kwargs[k]

            inputs_mm_data = inputs.get(k)
            if isinstance(inputs_mm_data, str):
                inputs_mm_data = [inputs_mm_data]
            inputs_mm_data = (inputs_mm_data or []).copy()
            if mm_data:
                assert not inputs_mm_data, f'self.{k}: {inputs_mm_data}'
            else:
                media_kwargs[k] = inputs_mm_data

        all_keys = set(f.name for f in fields(StdTemplateInputs))
        extra_kwargs = {k: v for k, v in inputs.items() if k not in all_keys}
        return cls(
            messages=messages,
            system=system,
            tools=tools,
            objects=objects,
            chat_template_kwargs=chat_template_kwargs,
            extra_kwargs=extra_kwargs,
            **kwargs,
            **media_kwargs)

    @staticmethod
    def remove_messages_media(messages: Messages) -> Dict[str, Any]:
        res = {'images': [], 'audios': [], 'videos': []}
        for message in messages:
            content = message['content']
            if isinstance(content, str):
                continue
            elif (isinstance(content, list) and content
                  and isinstance(content[0], int)) or (isinstance(content, dict) and 'token_ids' in content):
                continue
            # List[Dict[str, Any]]
            new_content = ''
            for item in content:
                key: str = item['type']
                value = item.get(key)
                if key == 'text':
                    new_content += value
                    continue
                # image/audio/video
                # image_url/audio_url/video_url
                if key.endswith('_url'):
                    key = key[:-len('_url')]
                new_content += f'<{key}>'
                if isinstance(value, dict):
                    value = value['url']
                if value:
                    res[f'{key}s'].append(value)
            message['content'] = new_content
        return res


@dataclass
class TemplateInputs:
    chosen: StdTemplateInputs  # or Dict[str, Any]
    rejected: Optional[StdTemplateInputs] = None
    positive: List[StdTemplateInputs] = field(default_factory=list)  # or Dict[str, Any]
    negative: List[StdTemplateInputs] = field(default_factory=list)

    def __post_init__(self):
        all_keys = set(f.name for f in fields(StdTemplateInputs))
        for key in ['chosen', 'rejected', 'positive', 'negative']:
            value_dict = getattr(self, key, None)
            if not isinstance(value_dict, dict):
                continue
            if key in {'chosen', 'rejected'}:
                setattr(self, key, StdTemplateInputs.from_dict(value_dict))
            else:
                res = []
                for i in range(len(value_dict['messages'])):
                    kwargs = {}
                    for k in all_keys:
                        val = value_dict.get(k)
                        if val is None:
                            continue
                        kwargs[k] = val[i]
                    res.append(StdTemplateInputs.from_dict(kwargs))
                setattr(self, key, res)

    @staticmethod
    def _compat_rejected_response(inputs: Dict[str, Any]):
        if 'rejected_response' not in inputs:
            return
        messages = inputs['messages']
        assert len(messages) > 0, f'messages: {messages}'
        idx = get_last_user_round(messages) + 1

        rejected_response = inputs.pop('rejected_response')
        if isinstance(rejected_response, str):
            rejected_responses = [{'role': 'assistant', 'content': rejected_response}]
        elif isinstance(rejected_response, list):
            rejected_responses = rejected_response
            for message in rejected_responses:
                if message['role'] == 'user':
                    raise ValueError(
                        f"The 'user' role is not allowed in 'rejected_response' messages. Found: {message}")
        else:
            raise ValueError(f'rejected_response must be a str or list. rejected_response: {rejected_response}')
        # Check that the response is different from the rejected_response.
        if len(messages[idx:]) == 1 and len(rejected_responses) == 1:
            response = messages[idx]['content']
            rejected_response = rejected_responses[0]['content']
            assert rejected_response != response, f'rejected_response: {rejected_response}, response: {response}'
        inputs['rejected_messages'] = deepcopy(messages[:idx]) + rejected_responses

    @classmethod
    def from_dict(cls, inputs: Dict[str, Any]) -> 'TemplateInputs':
        inputs = deepcopy(inputs)

        has_rejected_messages = inputs.get('rejected_messages') is not None
        cls._compat_rejected_response(inputs)
        kwargs = {}
        non_chosen_keys = ['rejected', 'positive', 'negative']
        for prefix in ['chosen'] + non_chosen_keys:
            if prefix == 'chosen':
                std_inputs = {
                    k: v
                    for k, v in inputs.items() if not any(k.startswith(f'{p}_') for p in non_chosen_keys)
                }
            else:
                std_inputs = {k[len(f'{prefix}_'):]: v for k, v in inputs.items() if k.startswith(f'{prefix}_')}
            if std_inputs:
                kwargs[prefix] = std_inputs

        if not has_rejected_messages and kwargs.get('rejected') is not None:
            chosen = kwargs['chosen']
            rejected = kwargs['rejected']
            # Supplement additional key-value pairs
            for k, chosen_v in chosen.items():
                rejected_v = rejected.get(k)
                if chosen_v is not None and rejected_v is None:
                    rejected[k] = chosen_v

        return cls(**kwargs)

def _preprocess_inputs(
    self,
    inputs: StdTemplateInputs,
) -> None:
    self._preprocess_tools(inputs)
    if self.model_meta.is_multimodal:
        self._replace_image_tags(inputs)
        self._replace_start_image_tags(inputs)

    images = inputs.images
    load_images = self.load_images or self.mode in {'vllm', 'lmdeploy'}
    load_images_origin = load_images
    max_pixels = self._get_max_pixels(inputs)
    if max_pixels is not None or inputs.objects:
        load_images = True
    if images:
        for i, image in enumerate(images):
            images[i] = self._load_image(images[i], load_images)
    if inputs.objects:
        self._get_height_width(inputs)
    if max_pixels is not None:
        # Scale the image proportionally without affecting the scaled objects.
        images = [rescale_image(img, max_pixels) for img in images]
    if images and not load_images_origin:  # fix pt & qwen-vl
        for i, image in enumerate(images):
            if isinstance(image, Image.Image):
                images[i] = self._save_pil_image(image)
    inputs.images = images

    # Resolve video/audio paths with ROOT_IMAGE_DIR.
    # Image paths are resolved by _load_image above, but video/audio paths are
    # passed as raw strings to model-specific templates. Templates that delegate
    # media loading to HF processors (e.g. Gemma4) need resolved absolute paths.
    if self.root_image_dir:
        for media_list in (inputs.videos, inputs.audios):
            for i, media_file in enumerate(media_list):
                if isinstance(media_file, str) and not media_file.startswith('http'):
                    media_list[i] = _check_path(media_file) or media_file

    if self.mode == 'vllm' and inputs.audios:
        sampling_rate = get_env_args('sampling_rate', int, None)
        inputs.audios = load_batch(
            inputs.audios, load_func=partial(load_audio, sampling_rate=sampling_rate, return_sr=True))
    if inputs.is_multimodal:
        self._add_default_tags(inputs)

@staticmethod
def _replace_image_tags(inputs: StdTemplateInputs):
    # compat
    if inputs.images:
        return
    images = []
    pattern = r'<img>(.+?)</img>'
    for message in inputs.messages:
        content = message['content']
        if not isinstance(content, str):
            continue
        for image in re.findall(pattern, content):
            # only support local_path
            if os.path.isfile(image):
                images.append(image)
            else:
                logger.warning_once(f'Failed to parse image path: `{content}`.', hash_id='<img></img>')
        message['content'] = re.sub(pattern, '<image>', content)
    inputs.images = images

@staticmethod
def _replace_start_image_tags(inputs: StdTemplateInputs):
    # compat
    generate_mode = False
    message = inputs.messages[-1]
    content = message['content']
    if message['role'] == 'user' and content.endswith('<start-image>'):
        generate_mode = True
        message['content'] = message['content'][:-len('<start-image>')]  # remove the <start-image>
    inputs.generate_mode = generate_mode

@staticmethod
def _extend_tokens(input_ids: List[int],
                   labels: Optional[List[int]],
                   loss_scale: Optional[List[float]],
                   replace_idx_list: List[int],
                   get_new_tokens: Callable[[int], List[int]],
                   mm_mask: Optional[List[bool]] = None):
    added_tokens_len = 0
    for i, idx in enumerate(replace_idx_list):
        try:
            new_tokens = get_new_tokens(i)
        except IndexError as e:
            logger.warning(f'IndexError occurs in the _extend_tokens function: {e}.')

def _encode(self, inputs: StdTemplateInputs) -> Dict[str, Any]:
    inputs.messages = deepcopy(inputs.messages)
    template_backend = self.template_backend
    if (self.template_meta.template_type == 'dummy' and self.use_chat_template and not self.is_training
            and self.task_type == 'causal_lm'):
        template_backend = 'jinja'
        logger.info_once(f'Setting template_backend: {template_backend}')
    self._swift_prepare_inputs(inputs)
    res_context_list, loss_scale_list, answer_len = (
        self._swift_encode(inputs) if template_backend == 'swift' else self._jinja_encode(inputs))
    encoded = {}
    if self.is_encoder_decoder:
        total_len = len(res_context_list)
        for key, _slice in zip(['prompt', 'answer'],
                               [slice(0, total_len - answer_len),
                                slice(total_len - answer_len, total_len)]):
            context_list, loss_scale = self._simplify_context_list(res_context_list[_slice],
                                                                   loss_scale_list[_slice], inputs)
            input_ids, labels, loss_scale = self._encode_context_list(context_list, loss_scale)
            encoded[f'{key}_input_ids'] = input_ids
            encoded[f'{key}_labels'] = labels
            encoded[f'{key}_loss_scale'] = loss_scale
        input_ids = encoded['prompt_input_ids'] + encoded['answer_input_ids']
        labels = encoded['prompt_labels'] + encoded['answer_labels']
        loss_scale = None
        if isinstance(encoded['prompt_loss_scale'], list):
            loss_scale = encoded['prompt_loss_scale'] + encoded['answer_loss_scale']
    else:
        res_context_list, loss_scale_list = self._simplify_context_list(res_context_list, loss_scale_list, inputs)
        input_ids, labels, loss_scale = self._encode_context_list(res_context_list, loss_scale_list)
    self._add_dynamic_eos(input_ids, labels, loss_scale, self._encode_context_list(self.template_meta.suffix)[0])

    encoded['input_ids'] = input_ids
    encoded['labels'] = labels
    encoded['loss_scale'] = loss_scale
    if encoded.get('labels') is not None:
        encoded['labels'][0] = -100
    if encoded.get('loss_scale') is not None:
        encoded['loss_scale'][0] = 0
    if not self.is_training:
        for k in list(encoded.keys()):
            if k.endswith('labels') or k.endswith('loss_scale'):
                encoded[k] = None
    return encoded

def _get_megatron_cp_length(self, length) -> int:
    cp_size = self.sequence_parallel_size
    if not self.use_megatron or cp_size == 1:
        return length
    return math.ceil(length / (cp_size * 2)) * (cp_size * 2)

def _handle_megatron_cp(self, batch: List[Dict[str, Any]]) -> None:
    cp_size = self.sequence_parallel_size
    if not self.use_megatron or cp_size == 1:
        return
    for encoded in batch:
        input_ids = encoded['input_ids']
        padding_len = math.ceil(len(input_ids) / (cp_size * 2)) * (cp_size * 2) - len(input_ids)
        input_ids += [self.tokenizer.pad_token_id] * padding_len
        if encoded.get('labels') is not None:
            encoded['labels'] += [-100] * padding_len
        if encoded.get('loss_scale') is not None:
            encoded['loss_scale'] += [0] * padding_len
        if encoded.get('length') is not None:
            encoded['length'] += padding_len
        if encoded.get('mm_token_type_ids') is not None:
            encoded['mm_token_type_ids'] = F.pad(encoded['mm_token_type_ids'], (0, padding_len), value=0)

